/* Apply fluid font-size to body text for optimal responsiveness */
body {
    font-family: 'Inter', sans-serif;
    font-size: clamp(1rem, 2vw + 0.5rem, 1.5rem); /* Min 16px, fluid (2vw+8px), Max 24px */
    line-height: 1.6;
    color: #333;
}

/* Example for a primary heading (h1) */
h1 {
    font-size: clamp(2rem, 5vw + 1rem, 4rem); /* Min 32px, fluid (5vw+16px), Max 64px */
    line-height: 1.1;
    font-weight: 700;
    margin-bottom: 0.5em;
}

/* Ensure smooth font rendering for web fonts */
body, h1, h2, h3, h4, h5, h6 {
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}
